public int mirrorReflection(int p, int q) {
    int m = p, n = q;
    int gcd;
    while (n != 0) {
        gcd = m % n;
        m = n;
        n = gcd;
    }

    if ((p / m) % 2 == 0) return 2;
    if ((q / m) % 2 == 0) return 0;
    return 1;
}
```

